# Decision logic for attention method selection
def choose_attention_method(seq_len, has_custom_kernels, task_type, gpu='a100'):
    """
    Practical heuristics for picking an attention variant.
    task_type: 'retrieval' | 'classification' | 'generation'
    """
    if seq_len <= 4096:
        return "FlashAttention (exact, best default for ≤4K)"

    if seq_len <= 32768 and has_custom_kernels:
        return "FlashAttention with sliding window (flash_attn window_size)"

    if task_type == 'retrieval' and has_custom_kernels:
        # Need precise attention for retrieval; use sparse patterns
        return "Longformer/BigBird (local + global tokens)"

    if task_type == 'classification':
        # Approximate is usually fine for classification
        if has_custom_kernels:
            return "Longformer (local + CLS global)"
        else:
            return "Linear attention (cosFormer or Performer)"

    if seq_len > 32768:
        return "SSM hybrid (Mamba-Transformer) or chunked sliding-window attention"

    return "Evaluate Longformer vs Performer on your specific task"
